import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/faq.md","filePath":"en/guide/faq.md","lastUpdated":1783349713000}'),r={name:"en/guide/faq.md"};function n(s,e,l,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="do-i-need-to-reboot-after-changing-the-config" tabindex="-1">Do I need to reboot after changing the config? <a class="header-anchor" href="#do-i-need-to-reboot-after-changing-the-config" aria-label="Permalink to &quot;Do I need to reboot after changing the config?&quot;">​</a></h2><p>No. The daemon watches <code>config.json</code> and hot-reloads scheduling within a minute; non-schedule fields like enable flags and thresholds are read at runtime and apply immediately. When editing by hand, use an atomic write (temp file, then replace).</p><h2 id="my-device-isn-t-f2fs-—-can-i-still-use-it" tabindex="-1">My device isn&#39;t F2FS — can I still use it? <a class="header-anchor" href="#my-device-isn-t-f2fs-—-can-i-still-use-it" aria-label="Permalink to &quot;My device isn&#39;t F2FS — can I still use it?&quot;">​</a></h2><p>Yes. Every feature except <strong>F2FS GC</strong> is independent of the filesystem type. On non-F2FS devices, set <code>gc.enabled</code> to <code>false</code>; everything else works normally.</p><h2 id="can-i-use-it-without-czerox" tabindex="-1">Can I use it without CZeroX? <a class="header-anchor" href="#can-i-use-it-without-czerox" aria-label="Permalink to &quot;Can I use it without CZeroX?&quot;">​</a></h2><p>Yes. The module runs fine on the default <code>config.json</code>. CZeroX just makes configuring and monitoring intuitive; without it you edit <code>config.json</code> by hand.</p><h2 id="which-root-solutions-are-supported" tabindex="-1">Which root solutions are supported? <a class="header-anchor" href="#which-root-solutions-are-supported" aria-label="Permalink to &quot;Which root solutions are supported?&quot;">​</a></h2><p>Magisk, KernelSU, and APatch.</p><h2 id="will-reinstalling-lose-my-settings" tabindex="-1">Will reinstalling lose my settings? <a class="header-anchor" href="#will-reinstalling-lose-my-settings" aria-label="Permalink to &quot;Will reinstalling lose my settings?&quot;">​</a></h2><p>At install you can choose to inherit the old config, which carries over the black/white lists and custom path list; but <code>config.json</code> is always reset to the new default, so re-adjust it after reinstalling if needed.</p><h2 id="what-happens-if-i-write-a-broken-config" tabindex="-1">What happens if I write a broken config? <a class="header-anchor" href="#what-happens-if-i-write-a-broken-config" aria-label="Permalink to &quot;What happens if I write a broken config?&quot;">​</a></h2><p>If the whole <code>config.json</code> fails to parse, the daemon <strong>keeps the last-good job set</strong> and never interrupts service. If only one job&#39;s <code>every</code> is invalid, <strong>only that job</strong> is skipped; the rest keep running.</p><h2 id="where-are-the-logs" tabindex="-1">Where are the logs? <a class="header-anchor" href="#where-are-the-logs" aria-label="Permalink to &quot;Where are the logs?&quot;">​</a></h2><p>With <code>general.log</code> on, logs are at <code>/data/adb/modules/CZero/log/&lt;YYYY-MM-DD&gt;.log</code>, keeping only today&#39;s file. Each line is tagged with its source component.</p><h2 id="could-cleaning-delete-my-data" tabindex="-1">Could cleaning delete my data? <a class="header-anchor" href="#could-cleaning-delete-my-data" aria-label="Permalink to &quot;Could cleaning delete my data?&quot;">​</a></h2><p>Cleaning targets only caches and leftover directories, with two layers of protection:</p><ul><li><strong>Temporal barrier</strong> — governed by <code>temporal_barrier_days</code>, only files older than N days are touched; for a more conservative setup, raise that value or narrow the scope.</li><li><strong>Recycle bin</strong> — other / custom-path cleaning <strong>does not truly delete</strong>. Files are first moved to the recycle bin and kept for <strong>7 days</strong> by default, fully recoverable to their original location during that window. So even an accidental removal can be undone. See <a href="/en/guide/features#recycle-bin-restore">Features · Recycle bin &amp; restore</a>.</li></ul><h2 id="i-deleted-a-file-by-mistake-—-how-do-i-restore-it" tabindex="-1">I deleted a file by mistake — how do I restore it? <a class="header-anchor" href="#i-deleted-a-file-by-mistake-—-how-do-i-restore-it" aria-label="Permalink to &quot;I deleted a file by mistake — how do I restore it?&quot;">​</a></h2><p>Cleaned files stay in the recycle bin for 7 days. View and restore them in CZeroX.</p><p>Restoring moves files back to their original paths as-is (preserving their original mtime). Sessions older than 7 days are purged automatically and can no longer be restored.</p><h2 id="where-do-i-report-issues" tabindex="-1">Where do I report issues? <a class="header-anchor" href="#where-do-i-report-issues" aria-label="Permalink to &quot;Where do I report issues?&quot;">​</a></h2><p>Please open one on <a href="https://github.com/Xocio/CZero/issues" target="_blank" rel="noreferrer">GitHub Issues</a>.</p>',23)])])}const f=t(r,[["render",n]]);export{g as __pageData,f as default};
